script.text:

function active$LaborContract(f) {
	f.add_onResponseComplete(on$LaborContract$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onChange$LaborContract$Tab);
  f._tabContainer._loaded = true;
	setDefault$LaborContract$Value(f);
  console.log(f._tinhChatHD);
  setItemAllowNulls(f, 'ngay_hl_den', (f._tinhChatHD == '2'));
}
function scatter$LaborContract(f) {setDefault$LaborContract$Value(f);}
function setDefault$LaborContract$Value(f) {
  if (f._action == 'New') {
		var d = new Date();
		f.setItemValue('ngay_ky_hd', d);
	}
  f.setReadOnlyFields('quoc_tich, ngay_sinh, noi_sinh');
}
function close$LaborContract(f) {
  try {f.remove_onResponseComplete(on$LaborContract$ResponseComplete)} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$LaborContract$Tab);} catch (ex) {}
}
function onChange$LaborContract$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['so_ld', 'dia_diem', 'phuong_tien', 'quoc_tich']);}
function onchange$LaborContract$IDNumber(o) {o.parentForm.request('IDNumber', 'IDNumber', ['ma_nv']);}
function onChange$ContractType(o) {o.parentForm.request('ContractType', 'ContractType', ['loai_hd']);}
function on$LaborContract$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'IDNumber':
      f.setItemControlBehavior('stt_rec', result[0].Value, true);
      f.setItemValue('ngay_sinh', result[1].Value);
      f.setItemControlBehavior('noi_sinh', result[2].Value, true);
      f.setItemValue('cmnd_ngay_hl', result[3].Value);
      f.setItemControlBehavior('cmnd_noi_cap', result[4].Value, true);
      f.setItemControlBehavior('chuc_danh', result[5].Value, true);
      f.setItemControlBehavior('chuc_danh2', result[6].Value, true);
      f.setItemControlBehavior('dia_chi_th_tru', result[7].Value, true);
      f.setItemControlBehavior('cmnd_so', result[8].Value, true);
      f.setItemControlBehavior('quoc_tich', result[9].Value, true);
      f.setItemControlBehavior('ten_bp%l', result[10].Value, true);
      f.live('dia_chi_th_tru');
      break;
    case 'ContractType':
      setItemAllowNulls(f, 'ngay_hl_den', (result[0].Value == '2'));
      break;
    default:
      break;
  }
}

function setItemAllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      o.field.AllowNulls = !v
      grandNode = o.parentNode.parentNode;
      if (v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
    }
  }
}
